-- Strummy seed — rebuilt schema (docs/DATABASE_REBUILD.md Step 6).
-- Idempotent reseed: backfills a profile for every auth user (role flags by email)
-- and restores the 438-song library. No raw auth.users inserts — those are
-- GoTrue-managed; on a genuinely fresh stack, sign up to create the admin, then
-- adjust flags. Safe to re-run.

set session_replication_role = 'replica';  -- bypass triggers/RLS side effects during bulk load

-- Profiles for existing auth users. Role flags by email — edit this mapping as the roster changes.
select
  u.id,
  u.email,
  nullif(u.raw_user_meta_data->>'first_name',''),
  nullif(u.raw_user_meta_data->>'last_name',''),
  coalesce(
    nullif(u.raw_user_meta_data->>'full_name',''),
    nullif(trim(concat_ws(' ', u.raw_user_meta_data->>'first_name', u.raw_user_meta_data->>'last_name')),''),
    u.email
  ),
  (u.email = 'p.romanczuk@gmail.com'),
  (u.email in ('p.romanczuk@gmail.com','teacher@example.com')),
  (u.email not in ('p.romanczuk@gmail.com','teacher@example.com'))
from auth.users u
on conflict (user_id) do nothing;

-- Song library restore (438 rows, captured 2026-07-18 pre-cutover).

set session_replication_role = 'origin';
